#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code for RQ 6.9.8)
# =============================================================================
"""
Step ID: step07
Step Name: Compile Summary Statistics and Theoretical Synthesis
RQ: results/ch6/6.9.8
Generated: 2026-01-20

PURPOSE:
Compile all results from correlation analysis, moderation test, and pooled effect size
to assess hypothesis support and provide theoretical interpretation of convergent NULL pattern.

EXPECTED INPUTS:
- results/ch6/6.9.8/data/step02_within_schema_correlations.csv (9 rows)
- results/ch6/6.9.8/data/step03_moderation_test.csv (6 rows)
- results/ch6/6.9.8/data/step05_weighted_combination.csv (1 row)
- results/ch6/6.9.8/data/step06_bootstrap_correlations.csv (9 rows)

EXPECTED OUTPUTS:
- results/ch6/6.9.8/data/step07_summary_statistics.csv (compiled summary table)
- results/ch6/6.9.8/data/step07_theoretical_synthesis.txt (theoretical interpretation)

VALIDATION CRITERIA:
- All expected statistics present
- Theoretical synthesis addresses all 3 hypotheses
- Clear statement of hypothesis support (yes/no with evidence)

g_code REASONING:
- Approach: Load all result files, compute summary statistics, assess hypotheses, synthesize
- Why this approach: Provides comprehensive evidence synthesis for final interpretation
- Data flow: Load results -> summarize -> assess hypotheses -> theoretical synthesis
- Expected performance: <5 seconds
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.8
LOG_FILE = RQ_DIR / "logs" / "step07_compile_summary.log"

# Input files
CORR_FILE = RQ_DIR / "data" / "step02_within_schema_correlations.csv"
MOD_FILE = RQ_DIR / "data" / "step03_moderation_test.csv"
POOLED_FILE = RQ_DIR / "data" / "step05_weighted_combination.csv"
BOOT_FILE = RQ_DIR / "data" / "step06_bootstrap_correlations.csv"

# Output files
SUMMARY_FILE = RQ_DIR / "data" / "step07_summary_statistics.csv"
SYNTHESIS_FILE = RQ_DIR / "data" / "step07_theoretical_synthesis.txt"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console with flush."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 07: Compile Summary Statistics and Theoretical Synthesis")

        # =====================================================================
        # STEP 1: Load All Result Files
        # =====================================================================
        log("[LOAD] Loading result files...")

        df_corr = pd.read_csv(CORR_FILE)
        log(f"[LOADED] Correlations: {len(df_corr)} rows")

        df_mod = pd.read_csv(MOD_FILE)
        log(f"[LOADED] Moderation test: {len(df_mod)} rows")

        df_pooled = pd.read_csv(POOLED_FILE)
        log(f"[LOADED] Pooled effect: {len(df_pooled)} rows")

        df_boot = pd.read_csv(BOOT_FILE)
        log(f"[LOADED] Bootstrap CIs: {len(df_boot)} rows")

        # =====================================================================
        # STEP 2: Compile Summary Statistics
        # =====================================================================
        log("[COMPILE] Computing summary statistics...")

        # Correlation summary
        corr_summary = {
            'min_r': df_corr['r'].min(),
            'max_r': df_corr['r'].max(),
            'mean_r': df_corr['r'].mean(),
            'sd_r': df_corr['r'].std(),
            'all_r_above_0.50': (df_corr['r'] > 0.50).all(),
            'all_r_positive': (df_corr['r'] > 0).all(),
            'n_bonferroni_sig': df_corr['sig_bonferroni'].sum()
        }

        log(f"[SUMMARY] Correlation range: [{corr_summary['min_r']:.3f}, {corr_summary['max_r']:.3f}]")
        log(f"[SUMMARY] Mean correlation: {corr_summary['mean_r']:.3f} (SD = {corr_summary['sd_r']:.3f})")
        log(f"[SUMMARY] All r > 0.50: {corr_summary['all_r_above_0.50']}")
        log(f"[SUMMARY] Bonferroni-significant: {corr_summary['n_bonferroni_sig']}/9")

        # Moderation test summary
        interaction_rows = df_mod[df_mod['term'].str.contains(':', regex=False)]
        moderation_summary = {
            'n_interaction_terms': len(interaction_rows),
            'interaction_terms': interaction_rows['term'].tolist(),
            'interaction_p_values': interaction_rows['p_value'].tolist(),
            'all_p_above_0.05': (interaction_rows['p_value'] > 0.05).all() if len(interaction_rows) > 0 else False,
            'max_interaction_p': interaction_rows['p_value'].max() if len(interaction_rows) > 0 else np.nan,
            'min_interaction_p': interaction_rows['p_value'].min() if len(interaction_rows) > 0 else np.nan
        }

        log(f"[SUMMARY] Interaction terms: {moderation_summary['n_interaction_terms']}")
        log(f"[SUMMARY] All interaction p > 0.05: {moderation_summary['all_p_above_0.05']}")
        if len(interaction_rows) > 0:
            log(f"[SUMMARY] Interaction p-value range: [{moderation_summary['min_interaction_p']:.4f}, {moderation_summary['max_interaction_p']:.4f}]")

        # Pooled effect summary
        pooled_summary = {
            'd_pooled': df_pooled['d_pooled'].values[0],
            'SE_pooled': df_pooled['SE_pooled'].values[0],
            'CI_lower': df_pooled['CI_lower'].values[0],
            'CI_upper': df_pooled['CI_upper'].values[0],
            'negligible': abs(df_pooled['d_pooled'].values[0]) < 0.20,
            'interpretation': df_pooled['interpretation'].values[0]
        }

        log(f"[SUMMARY] Pooled effect: d = {pooled_summary['d_pooled']:.3f} [{pooled_summary['CI_lower']:.3f}, {pooled_summary['CI_upper']:.3f}]")
        log(f"[SUMMARY] Negligible effect: {pooled_summary['negligible']}")

        # Bootstrap summary
        bootstrap_summary = {
            'n_comparisons': len(df_boot),
            'n_agreement': df_boot['agreement'].sum(),
            'agreement_rate': df_boot['agreement'].mean()
        }

        log(f"[SUMMARY] Bootstrap agreement: {bootstrap_summary['n_agreement']}/{bootstrap_summary['n_comparisons']} ({bootstrap_summary['agreement_rate']*100:.1f}%)")

        # =====================================================================
        # STEP 3: Assess Hypothesis Support
        # =====================================================================
        log("[ASSESS] Evaluating hypothesis support...")

        # Primary hypothesis: Schema does NOT moderate confidence-accuracy relationship
        # Evidence: (1) correlations similar across conditions, (2) interaction terms non-significant
        primary_supported = (
            corr_summary['all_r_above_0.50'] and
            moderation_summary['all_p_above_0.05'] and
            corr_summary['sd_r'] < 0.10
        )

        log(f"[HYPOTHESIS] Primary (schema NOT moderate): {primary_supported}")
        log(f"  - All r > 0.50: {corr_summary['all_r_above_0.50']}")
        log(f"  - All interaction p > 0.05: {moderation_summary['all_p_above_0.05']}")
        log(f"  - SD(r) < 0.10: {corr_summary['sd_r'] < 0.10} (SD = {corr_summary['sd_r']:.3f})")

        # Secondary hypothesis 1: Both measures show NULL schema effect
        secondary1_supported = pooled_summary['negligible']

        log(f"[HYPOTHESIS] Secondary 1 (both measures NULL): {secondary1_supported}")
        log(f"  - |d_pooled| < 0.20: {pooled_summary['negligible']} (|d| = {abs(pooled_summary['d_pooled']):.3f})")

        # Secondary hypothesis 2: Combined effect negligible (CI excludes 0.20)
        secondary2_supported = (
            pooled_summary['CI_lower'] > -0.20 and
            pooled_summary['CI_upper'] < 0.20
        )

        log(f"[HYPOTHESIS] Secondary 2 (CI excludes 0.20): {secondary2_supported}")
        log(f"  - CI [{pooled_summary['CI_lower']:.3f}, {pooled_summary['CI_upper']:.3f}] within [-0.20, 0.20]: {secondary2_supported}")

        # Overall conclusion
        all_supported = primary_supported and secondary1_supported and secondary2_supported

        log(f"[CONCLUSION] All hypotheses supported: {all_supported}")

        # =====================================================================
        # STEP 4: Theoretical Synthesis
        # =====================================================================
        log("[SYNTHESIS] Generating theoretical interpretation...")

        synthesis_lines = []
        synthesis_lines.append("=" * 80)
        synthesis_lines.append("THEORETICAL SYNTHESIS - RQ 6.9.8")
        synthesis_lines.append("Schema Congruence Convergent NULL Explanation")
        synthesis_lines.append("=" * 80)
        synthesis_lines.append("")

        if all_supported:
            synthesis_lines.append("CONVERGENT NULL PATTERN CONFIRMED")
            synthesis_lines.append("")
            synthesis_lines.append("Evidence Summary:")
            synthesis_lines.append(f"  1. Confidence-accuracy correlations EQUAL across schema conditions")
            synthesis_lines.append(f"     - Mean r = {corr_summary['mean_r']:.3f} (SD = {corr_summary['sd_r']:.3f})")
            synthesis_lines.append(f"     - Range: [{corr_summary['min_r']:.3f}, {corr_summary['max_r']:.3f}]")
            synthesis_lines.append(f"     - All r > 0.50: {corr_summary['all_r_above_0.50']}")
            synthesis_lines.append("")
            synthesis_lines.append(f"  2. NO moderation by schema congruence")
            synthesis_lines.append(f"     - Interaction p-values: {moderation_summary['interaction_p_values']}")
            synthesis_lines.append(f"     - All p > 0.05: {moderation_summary['all_p_above_0.05']}")
            synthesis_lines.append("")
            synthesis_lines.append(f"  3. Combined effect size negligible")
            synthesis_lines.append(f"     - Pooled d = {pooled_summary['d_pooled']:.3f} [{pooled_summary['CI_lower']:.3f}, {pooled_summary['CI_upper']:.3f}]")
            synthesis_lines.append(f"     - |d| < 0.20: {pooled_summary['negligible']}")
            synthesis_lines.append(f"     - CI excludes 0.20: {secondary2_supported}")
            synthesis_lines.append("")
            synthesis_lines.append("THEORETICAL INTERPRETATION:")
            synthesis_lines.append("")
            synthesis_lines.append("VR Episodic Encoding Hypothesis SUPPORTED")
            synthesis_lines.append("")
            synthesis_lines.append("Immersive VR creates context-rich episodic traces that rely on")
            synthesis_lines.append("spatial-temporal binding rather than semantic schema matching.")
            synthesis_lines.append("Unitized encoding in rich 3D environments bypasses schema-based")
            synthesis_lines.append("processing mechanisms that dominate traditional word-list paradigms.")
            synthesis_lines.append("")
            synthesis_lines.append("Both memory performance AND metacognitive monitoring operate on")
            synthesis_lines.append("episodic trace strength rather than schema-based familiarity,")
            synthesis_lines.append("explaining the convergent NULL pattern across accuracy and confidence.")
            synthesis_lines.append("")
            synthesis_lines.append("This dissociation from semantic schema processing represents a")
            synthesis_lines.append("fundamental shift in how memory operates in immersive VR environments.")
        else:
            synthesis_lines.append("CONVERGENT NULL PATTERN NOT CONFIRMED")
            synthesis_lines.append("")
            synthesis_lines.append("One or more hypotheses NOT supported:")
            synthesis_lines.append(f"  - Primary hypothesis (no moderation): {primary_supported}")
            synthesis_lines.append(f"  - Secondary 1 (both measures NULL): {secondary1_supported}")
            synthesis_lines.append(f"  - Secondary 2 (CI excludes 0.20): {secondary2_supported}")
            synthesis_lines.append("")
            synthesis_lines.append("Alternative Explanations Required:")
            synthesis_lines.append("")
            if not primary_supported:
                synthesis_lines.append("  - Schema moderation MAY be present (interaction terms or high SD(r))")
                synthesis_lines.append("  - VR encoding may not fully bypass schema-based processing")
            if not secondary1_supported:
                synthesis_lines.append("  - Combined effect size non-negligible (|d| >= 0.20)")
                synthesis_lines.append("  - Schema congruence effects may exist across measures")
            if not secondary2_supported:
                synthesis_lines.append("  - Confidence interval includes non-negligible effect sizes")
                synthesis_lines.append("  - Uncertainty too high to confirm convergent NULL")

        synthesis_lines.append("")
        synthesis_lines.append("LIMITATIONS:")
        synthesis_lines.append("")
        synthesis_lines.append("1. K=2 measures insufficient for formal meta-analysis")
        synthesis_lines.append("   - No heterogeneity statistics (I², Q-test)")
        synthesis_lines.append("   - Simple inverse-variance weighting only")
        synthesis_lines.append("")
        synthesis_lines.append("2. Test-retest design (4 sessions) may create practice effects")
        synthesis_lines.append("   - Repeated exposure to same schema categories")
        synthesis_lines.append("   - Learning effects could attenuate schema congruence impacts")
        synthesis_lines.append("")
        synthesis_lines.append("3. Encoding quality confound not directly tested")
        synthesis_lines.append("   - Intercept vs slope distinction (D059) not addressed")
        synthesis_lines.append("   - Schema may affect encoding quality (intercept) but not")
        synthesis_lines.append("     confidence-accuracy relationship (slope)")
        synthesis_lines.append("")
        synthesis_lines.append("4. IRT scale compatibility assumed")
        synthesis_lines.append("   - Both Ch5 5.4.1 and Ch6 6.5.1 used comparable IRT models")
        synthesis_lines.append("   - Verify both used same item sets and calibration approach")
        synthesis_lines.append("")
        synthesis_lines.append("=" * 80)

        synthesis_text = "\n".join(synthesis_lines)

        # =====================================================================
        # STEP 5: Create Summary Table
        # =====================================================================
        log("[COMPILE] Creating summary statistics table...")

        summary_data = {
            'statistic': [
                'correlation_min',
                'correlation_max',
                'correlation_mean',
                'correlation_sd',
                'all_r_above_0.50',
                'bonferroni_significant_count',
                'interaction_terms_count',
                'all_interaction_p_above_0.05',
                'pooled_d',
                'pooled_d_CI_lower',
                'pooled_d_CI_upper',
                'pooled_d_negligible',
                'bootstrap_agreement_rate',
                'primary_hypothesis_supported',
                'secondary1_hypothesis_supported',
                'secondary2_hypothesis_supported',
                'overall_convergent_null_confirmed'
            ],
            'value': [
                corr_summary['min_r'],
                corr_summary['max_r'],
                corr_summary['mean_r'],
                corr_summary['sd_r'],
                corr_summary['all_r_above_0.50'],
                corr_summary['n_bonferroni_sig'],
                moderation_summary['n_interaction_terms'],
                moderation_summary['all_p_above_0.05'],
                pooled_summary['d_pooled'],
                pooled_summary['CI_lower'],
                pooled_summary['CI_upper'],
                pooled_summary['negligible'],
                bootstrap_summary['agreement_rate'],
                primary_supported,
                secondary1_supported,
                secondary2_supported,
                all_supported
            ]
        }

        df_summary = pd.DataFrame(summary_data)

        # =====================================================================
        # STEP 6: Validate Output
        # =====================================================================
        log("[VALIDATION] Checking summary compilation...")

        errors = []

        # Check all expected statistics present
        expected_stats = [
            'correlation_mean', 'pooled_d', 'primary_hypothesis_supported',
            'secondary1_hypothesis_supported', 'secondary2_hypothesis_supported',
            'overall_convergent_null_confirmed'
        ]

        missing_stats = [stat for stat in expected_stats if stat not in df_summary['statistic'].values]
        if missing_stats:
            errors.append(f"Missing statistics: {missing_stats}")
        else:
            log("[PASS] All expected statistics present")

        # Check theoretical synthesis addresses all 3 hypotheses
        required_keywords = ['primary', 'secondary', 'hypothesis', 'supported']
        synthesis_lower = synthesis_text.lower()
        missing_keywords = [kw for kw in required_keywords if kw not in synthesis_lower]
        if missing_keywords:
            errors.append(f"Synthesis missing keywords: {missing_keywords}")
        else:
            log("[PASS] Theoretical synthesis addresses all hypotheses")

        # Check limitations section
        if 'LIMITATIONS:' not in synthesis_text:
            errors.append("Synthesis missing LIMITATIONS section")
        else:
            log("[PASS] Limitations section included")

        # Check clear statement of support
        if all_supported:
            if 'CONVERGENT NULL PATTERN CONFIRMED' not in synthesis_text:
                errors.append("Synthesis doesn't state CONFIRMED when all hypotheses supported")
        else:
            if 'CONVERGENT NULL PATTERN NOT CONFIRMED' not in synthesis_text:
                errors.append("Synthesis doesn't state NOT CONFIRMED when hypotheses not supported")

        if not errors:
            log("[PASS] Clear statement of hypothesis support")

        # =====================================================================
        # STEP 7: Save Outputs
        # =====================================================================
        if errors:
            log("[VALIDATION] FAIL - Errors detected:")
            for error in errors:
                log(f"  - {error}")
            raise ValueError(f"Validation failed with {len(errors)} error(s)")

        log("[VALIDATION] PASS - All checks passed")

        df_summary.to_csv(SUMMARY_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] Summary statistics: {SUMMARY_FILE}")

        with open(SYNTHESIS_FILE, 'w', encoding='utf-8') as f:
            f.write(synthesis_text)
        log(f"[SAVED] Theoretical synthesis: {SYNTHESIS_FILE}")

        log("[SUMMARY] Summary statistics compiled")
        log("[SUMMARY] Theoretical synthesis complete")
        log(f"[SUMMARY] Primary hypothesis: {'SUPPORTED' if primary_supported else 'NOT SUPPORTED'}")
        log(f"[SUMMARY] Overall convergent NULL: {'CONFIRMED' if all_supported else 'NOT CONFIRMED'}")

        log("[SUCCESS] Step 07 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        import traceback
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
